solution_code:
#include <iostream>

void incrementIfPositive(int* ptr) {
    if (*ptr > 0)
        *ptr += 1;
}

int main() {
    int n {};
    std::cin >> n;
    incrementIfPositive(&n);
    std::cout << n << '\n';
    return 0;
}
